What does this program print? (Answer with one integer per line.)

```cpp
#include <random>
#include <iostream>
int main()
{
    std::mt19937 rng{ 0u };
    std::uniform_int_distribution<int> d{ 1, 4 };
    std::cout << d(rng) << '\n';
    std::cout << d(rng) << '\n';
}
```

The student wants a uniform distribution over integers 1 through 6. What is wrong?

```cpp
#include <random>
#include <iostream>
int main()
{
    std::mt19937 rng{ 99u };
    std::uniform_int_distribution<int> d{ rng(), 6 };
    std::cout << d(rng) << '\n';
}
```

What does this program print?

```cpp
#include <random>
#include <iostream>
int main()
{
    std::mt19937 rng{ 5u };
    std::mt19937 rng2{ 5u };
    std::uniform_int_distribution<int> d{ 0, 1 };
    std::cout << d(rng) << ' ' << d(rng) << '\n';
    std::cout << d(rng2) << ' ' << d(rng2) << '\n';
}
```
